// WHY NOT THE AI AGENT NODE?
// Same reasoning as the Ollama build: the LangChain Agent node runs a ReAct loop
// (several LLM round-trips, a scratchpad, tool-choice reasoning) — none of which this
// lab needs. For a conversation you must not keep waiting for, that overhead is the
// whole difference between "interactive" and "awkward". So we build the chat payload
// ourselves and call OpenAI once.
//
// History comes from the BROWSER (it already has the transcript), which also keeps this
// flow stateless — no memory node, no session store.

const body = $input.first().json.body || {};
const message = (body.message || '').toString().trim();
const history = Array.isArray(body.history) ? body.history.slice(-6) : [];

const SYSTEM = `You are Aria, a friendly AI receptionist for Tertiary Infotech Academy.

You are SPOKEN ALOUD by a talking avatar, so:
- Reply in ONE short sentence. Two at the very most.
- Plain spoken English. No markdown, no bullets, no emoji, no URLs.
- Say numbers in words: "two days", "nine thirty in the morning".
- If you do not know, say so briefly and offer a colleague follow-up. Never invent a price, a date or a policy.

WHAT YOU KNOW
- The academy runs WSQ short courses in AI, automation and data.
- Classes run 9:30am to 6:30pm on weekdays at our training centre.
- Course fees vary; funding is available for eligible Singaporeans.
- To enrol, a learner registers on the website.`;

const messages = [
  { role: 'system', content: SYSTEM },
  ...history.map((h) => ({ role: h.role === 'you' ? 'user' : 'assistant', content: h.text })),
  { role: 'user', content: message || 'Hello' },
];

// The Ollama twin needed `think: false` and `keep_alive` — both are Ollama-only concerns
// (a local thinking model burning its budget on an inner monologue, and a 9.6 GB model
// being evicted from RAM). A hosted model has neither problem, so the payload is smaller.
return [{ json: {
  openai: {
    model: 'gpt-4.1-mini',
    stream: false,
    messages,
    max_tokens: 120,      // enough for two spoken sentences, not enough to ramble
    temperature: 0.6,
  },
  warm: !!body.warm,
  started_at: Date.now(), // OpenAI does not report timings, so we measure them ourselves
} }];

// The avatar SPEAKS this, so strip anything that does not read aloud: a stray asterisk
// becomes an audible "asterisk" in the browser's voice.
const res = $input.first().json;
const started = $('Build Chat Request').first().json.started_at;

const choice = (res.choices && res.choices[0]) || {};
let reply = (choice.message?.content || '').toString();
// OpenAI's equivalent of Ollama's done_reason: 'length' — the model was cut off mid-sentence.
const starved = !reply && choice.finish_reason === 'length';

reply = reply
  .replace(/[*_`#>]/g, '')
  .replace(/^\s*[-•]\s*/gm, '')
  .replace(/https?:\/\/\S+/g, 'the link on our website')
  .replace(/\s+/g, ' ')
  .trim();

if (!reply) {
  reply = res.error
    ? 'My brain is not answering. Check the OpenAI credential and your remaining credits.'
    : starved
      ? 'Sorry, I ran out of words. Ask me that again?'
      : 'Sorry, I did not catch that. Could you say it again?';
}

// Report where the time went, so the lab can SHOW the latency rather than claim it.
// Ollama hands back nanosecond timings per phase; OpenAI gives none, so total_ms is
// wall-clock measured across the HTTP call and the token counts come from `usage`.
const usage = res.usage || {};

return [{ json: {
  reply,
  timing: {
    total_ms: started ? Date.now() - started : null,
    model_load_ms: null,   // not applicable: the model is already hot on OpenAI's side
    prompt_ms: null,       // OpenAI does not break the latency down by phase
    generate_ms: null,
    tokens: usage.completion_tokens || 0,
    prompt_tokens: usage.prompt_tokens || 0,
  },
} }];
